import 'package:flutter/material.dart';import '../models/budget.dart';import '../models/recurring_payment.dart';import '../models/transaction.dart';import '../services/mock_data_service.dart';class InsightsProvider with ChangeNotifier {  List<Transaction> _recentTransactions = [];  List<Budget> _budgets = [];  List<RecurringPayment> _recurringPayments = [];  double _currentMonthSpending = 0.0;  List<Transaction> get recentTransactions => _recentTransactions;  List<Budget> get budgets => _budgets;  List<RecurringPayment> get recurringPayments => _recurringPayments;  double get currentMonthSpending => _currentMonthSpending;  InsightsProvider() {    _loadInsightsData();  }  void _loadInsightsData() {    _recentTransactions = MockDataService.transactions        .where((t) => t.amount < 0)        .take(5)        .toList();    _budgets = MockDataService.budgets;    _recurringPayments = MockDataService.recurringPayments;    _currentMonthSpending = MockDataService.getCurrentMonthSpending();    notifyListeners();  }  void addTransaction(Transaction transaction) {    // In a real app, this would interact with a backend    // For mock, we just add it to the list and notify    MockDataService.transactions.insert(0, transaction);    _loadInsightsData(); // Reload all data to ensure consistency  }  void updateTransaction(Transaction updatedTransaction) {    final index = MockDataService.transactions        .indexWhere((t) => t.id == updatedTransaction.id);    if (index != -1) {      MockDataService.transactions[index] = updatedTransaction;      _loadInsightsData();    }  }  void addBudget(Budget budget) {    MockDataService.budgets.add(budget);    _loadInsightsData();  }  void updateBudget(Budget updatedBudget) {    final index = MockDataService.budgets.indexWhere((b) => b.id == updatedBudget.id);    if (index != -1) {      MockDataService.budgets[index] = updatedBudget;      _loadInsightsData();    }  }  void deleteBudget(String budgetId) {    MockDataService.budgets.removeWhere((b) => b.id == budgetId);    _loadInsightsData();  }}